  ('elementary-7fec267e-moex-00391', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '一國面對景氣衰退時，政府往往會透過某些措施的採行，刺激景氣復甦，帶動經濟成長。下列何者無法 達成刺激景氣復甦的目標？', '["增加公共投資", "降低重貼現率", "獎勵民間投資", "取消補貼政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00392', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '若世界僅由甲、乙兩國組成，且甲國生產所有商品的效率皆比乙國的水準高。若以機會成本的觀點而言， 下列有關甲、乙兩國生產及貿易的敘述，何者正確？', '["甲國生產所有商品均具絕對利益", "乙國向甲國進口所有產品最有利", "甲國生產所有商品的機會成本低於乙國", "若兩國進行分工，甲、乙兩國的生產可能線會內縮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00393', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '大學剛畢業的小湘有三個工作機會與繼續升學的道路可選擇，一是月薪2萬5千元的家教老師；另一是 月薪2萬8千元的房屋仲介；以及月薪3萬元的法務助理；若選擇不就業，繼續進入研究所碩士班就讀， 學雜費兩年共需20萬元。依上述資料判斷，在不考慮其他條件的情況下，針對小湘大學畢業後兩年間做 選擇的機會成本之敘述，下列何者正確？', '["若當家教老師，機會成本為67萬2千元", "若選擇當房屋仲介，外顯成本為72萬元", "若選擇就學，外顯成本為72萬元", "若選擇就學，機會成本為92萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
